### Custom Hook для сложного состояния формы

Промышленный хук формы отслеживает значения полей, посещённые поля, ошибки валидации и async-отправку. Ключевой дизайн: валидация на blur (не только на submit), отслеживание `touched` для избежания преждевременных ошибок, `useReducer` для сложных переходов состояния.

```typescript
import { useReducer, useCallback } from 'react';

type Values = Record<string, string>;
type Errors = Record<string, string>;
type Touched = Record<string, boolean>;

type FormState = { values: Values; errors: Errors; touched: Touched; isSubmitting: boolean };
type Action =
  | { type: 'CHANGE'; field: string; value: string }
  | { type: 'BLUR'; field: string }
  | { type: 'SET_ERRORS'; errors: Errors }
  | { type: 'SUBMIT_START' }
  | { type: 'SUBMIT_END' };

function reducer(state: FormState, action: Action): FormState {
  switch (action.type) {
    case 'CHANGE': return { ...state, values: { ...state.values, [action.field]: action.value } };
    case 'BLUR':   return { ...state, touched: { ...state.touched, [action.field]: true } };
    case 'SET_ERRORS': return { ...state, errors: action.errors };
    case 'SUBMIT_START': return { ...state, isSubmitting: true };
    case 'SUBMIT_END':   return { ...state, isSubmitting: false };
    default: return state;
  }
}

function useForm(
  initialValues: Values,
  validate: (values: Values) => Errors, // validate ИСПОЛЬЗУЕТСЯ — на blur и submit
  onSubmit: (values: Values) => Promise<void>
) {
  const [state, dispatch] = useReducer(reducer, {
    values: initialValues, errors: {}, touched: {}, isSubmitting: false,
  });

  const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) =>
    dispatch({ type: 'CHANGE', field: e.target.name, value: e.target.value }), []);

  const handleBlur = useCallback((e: React.FocusEvent<HTMLInputElement>) => {
    dispatch({ type: 'BLUR', field: e.target.name });
    dispatch({ type: 'SET_ERRORS', errors: validate(state.values) }); // валидация на blur
  }, [validate, state.values]);

  const handleSubmit = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    const errors = validate(state.values); // валидация перед отправкой
    if (Object.keys(errors).length > 0) {
      dispatch({ type: 'SET_ERRORS', errors });
      return;
    }
    dispatch({ type: 'SUBMIT_START' });
    try { await onSubmit(state.values); }
    finally { dispatch({ type: 'SUBMIT_END' }); }
  }, [validate, onSubmit, state.values]);

  const isValid = Object.keys(validate(state.values)).length === 0;
  return { ...state, handleChange, handleBlur, handleSubmit, isValid };
}

// Использование
function LoginForm() {
  const { values, errors, touched, handleChange, handleBlur, handleSubmit, isSubmitting } =
    useForm(
      { email: '', password: '' },
      ({ email, password }) => {
        const e: Errors = {};
        if (!email.includes('@')) e.email = 'Некорректный email';
        if (password.length < 8)  e.password = 'Минимум 8 символов';
        return e;
      },
      async (values) => { await api.login(values); }
    );

  return (
    <form onSubmit={handleSubmit}>
      <input name="email" value={values.email} onChange={handleChange} onBlur={handleBlur} />
      {touched.email && errors.email && <span>{errors.email}</span>}
      <input type="password" name="password" value={values.password} onChange={handleChange} onBlur={handleBlur} />
      {touched.password && errors.password && <span>{errors.password}</span>}
      <button type="submit" disabled={isSubmitting}>Войти</button>
    </form>
  );
}
```

**Типичная ошибка на интервью:** Показывать ошибки во всех полях до того, как пользователь их посетил — плохой UX. Карта `touched` обеспечивает показ ошибок только после посещения поля. Вторая ловушка: забыть очистить ошибки при успешной отправке, оставив устаревшие сообщения даже после сброса формы.

