answer.en:
### Custom Hook + Context for Shared Form State

Context avoids prop-drilling for form data that is consumed in deeply-nested children. The pattern: one context value produced by a custom hook, consumed anywhere below the provider.

```typescript
import { createContext, useContext, useReducer, useCallback, type ReactNode } from 'react';

type FormValues = { email: string; password: string };
type FormErrors = Partial<Record<keyof FormValues, string>>;

type FormContextValue = {
  values: FormValues;
  errors: FormErrors;
  handleChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
  handleSubmit: (e: React.FormEvent) => void;
};

const FormContext = createContext<FormContextValue | null>(null);

function useFormContext() {
  const ctx = useContext(FormContext);
  if (!ctx) throw new Error('useFormContext must be used within FormProvider');
  return ctx;
}

type State = { values: FormValues; errors: FormErrors };
type Action = { type: 'CHANGE'; field: keyof FormValues; value: string } | { type: 'SET_ERRORS'; errors: FormErrors };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'CHANGE': return { ...state, values: { ...state.values, [action.field]: action.value } };
    case 'SET_ERRORS': return { ...state, errors: action.errors };
    default: return state;
  }
}

function validate(values: FormValues): FormErrors {
  const errors: FormErrors = {};
  if (!values.email.includes('@')) errors.email = 'Invalid email';
  if (values.password.length < 8)  errors.password = 'Min 8 characters';
  return errors;
}

export function FormProvider({ children, onSubmit }: { children: ReactNode; onSubmit: (v: FormValues) => void }) {
  const [state, dispatch] = useReducer(reducer, {
    values: { email: '', password: '' },
    errors: {},
  });

  const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) =>
    dispatch({ type: 'CHANGE', field: e.target.name as keyof FormValues, value: e.target.value }), []);

  const handleSubmit = useCallback((e: React.FormEvent) => {
    e.preventDefault();
    const errors = validate(state.values);
    if (Object.keys(errors).length > 0) {
      dispatch({ type: 'SET_ERRORS', errors });
      return;
    }
    onSubmit(state.values);
  }, [state.values, onSubmit]);

  return (
    <FormContext.Provider value={{ ...state, handleChange, handleSubmit }}>
      {children}
    </FormContext.Provider>
  );
}

// Deeply-nested field — no props needed, reads context directly
function EmailField() {
  const { values, errors, handleChange } = useFormContext();
  return (
    <div>
      <input name="email" value={values.email} onChange={handleChange} />
      {errors.email && <span style={{ color: 'red' }}>{errors.email}</span>}
    </div>
  );
}

function PasswordField() {
  const { values, errors, handleChange } = useFormContext();
  return (
    <div>
      <input type="password" name="password" value={values.password} onChange={handleChange} />
      {errors.password && <span style={{ color: 'red' }}>{errors.password}</span>}
    </div>
  );
}

function SubmitButton() {
  const { handleSubmit } = useFormContext();
  return <button onClick={handleSubmit}>Login</button>;
}

// Usage
function LoginPage() {
  return (
    <FormProvider onSubmit={values => console.log('Submitted:', values)}>
      <EmailField />
      <PasswordField />
      <SubmitButton />
    </FormProvider>
  );
}
```

**Common interview trap:** Calling a hook inside a JSX expression — `value={useMyHook()}` is a Rules of Hooks violation (hooks cannot be called inside object expressions or JSX). Always call hooks at the top level of a component or custom hook. Another trap: not memoizing the context value — a new object on every render triggers re-renders in all consumers even if the data didn't change. Use `useMemo` or `useReducer` (which returns stable dispatch) to keep the value stable.

