  }, [state.values, onSubmit]);

  return (
    <FormContext.Provider value={{ ...state, handleChange, handleSubmit }}>
      {children}
    </FormContext.Provider>
  );
}

// Глубоко вложенное поле — пропсы не нужны, читает контекст напрямую
function EmailField() {
  const { values, errors, handleChange } = useFormContext();
  return (
    <div>
      <input name="email" value={values.email} onChange={handleChange} />
      {errors.email && <span style={{ color: 'red' }}>{errors.email}</span>}
    </div>
  );
}

function PasswordField() {
  const { values, errors, handleChange } = useFormContext();
  return (
    <div>
      <input type="password" name="password" value={values.password} onChange={handleChange} />
      {errors.password && <span style={{ color: 'red' }}>{errors.password}</span>}
    </div>
  );
}

function SubmitButton() {
  const { handleSubmit } = useFormContext();
  return <button onClick={handleSubmit}>Войти</button>;
}

// Использование
function LoginPage() {
  return (
    <FormProvider onSubmit={values => console.log('Отправлено:', values)}>
      <EmailField />
      <PasswordField />
      <SubmitButton />
    </FormProvider>
  );
}
```

**Типичная ошибка на интервью:** Вызов хука внутри JSX-выражения — `value={useMyHook()}` нарушает правила хуков (хуки нельзя вызывать внутри объектных выражений или JSX). Всегда вызывайте хуки на верхнем уровне компонента или custom hook. Вторая ловушка: не мемоизировать значение контекста — новый объект при каждом рендере вызывает перерендер всех потребителей, даже если данные не изменились. Используйте `useMemo` или `useReducer` (который возвращает стабильный dispatch).

answer.en:
### Controlled vs Uncontrolled Inputs

Controlled inputs have React state driving the value; uncontrolled use refs. Controlled inputs offer predictability and easy validation; uncontrolled are simpler but harder to validate. Use controlled for forms, uncontrolled for file inputs or integrations.

```typescript
// Controlled
const [value, setValue] = useState('');
<input value={value} onChange={e => setValue(e.target.value)} />

// Uncontrolled
const inputRef = useRef();
<input ref={inputRef} />
console.log(inputRef.current.value);
```

**Common interview trap:** Mixing controlled and uncontrolled props on same element causes React warnings and unpredictable behavior.

answer.ru:
### Управляемые vs неуправляемые инпуты

Управляемые инпуты используют React состояние; неуправляемые используют refs. Управляемые обеспечивают предсказуемость и легкую валидацию; неуправляемые проще, но сложнее валидировать. Используйте управляемые для форм, неуправляемые для file input.

```typescript
// Управляемый
const [value, setValue] = useState('');
<input value={value} onChange={e => setValue(e.target.value)} />

// Неуправляемый
const inputRef = useRef();
<input ref={inputRef} />
console.log(inputRef.current.value);
```

**Типичная ошибка:** Смешивание управляемых и неуправляемых пропсов вызывает предупреждения React и непредсказуемое поведение.

answer.en:
### React utilities for different concerns

React.memo prevents unnecessary re-renders of pure components. Error Boundaries catch render errors. Portals render outside DOM hierarchy (modals). Fragments group elements without adding DOM nodes.

```typescript
const MemoChild = React.memo(({ data }) => <div>{data}</div>);

class ErrorBoundary extends React.Component {
  componentDidCatch(err) { /* handle */ }
  render() { return this.props.children; }
}

const Modal = () => ReactDOM.createPortal(<div>Modal</div>, document.body);
const List = () => <>{items.map(i => <Item key={i.id} />)}</>
```

**Common interview trap:** React.memo with objects/functions in props doesn't prevent re-renders; useCallback/useMemo needed for props.

answer.ru:
### React утилиты для разных задач

React.memo предотвращает ненужные ре-рендеры чистых компонентов. Error Boundaries ловят ошибки рендера. Portals рендерят вне иерархии DOM. Fragments группируют элементы без DOM узлов.

```typescript
const MemoChild = React.memo(({ data }) => <div>{data}</div>);

class ErrorBoundary extends React.Component {
  componentDidCatch(err) { /* handle */ }
  render() { return this.props.children; }
}

const Modal = () => ReactDOM.createPortal(<div>Modal</div>, document.body);
const List = () => <>{items.map(i => <Item key={i.id} />)}</>
```

**Типичная ошибка:** React.memo с объектами/функциями в пропсах не предотвращает ре-рендеры; нужны useCallback/useMemo.

answer.en:
### React Fiber Architecture

Fiber is the complete reimplementation of React's reconciliation algorithm (React 16+). The core insight: rendering must be **interruptible** so high-priority updates (user input) can preempt low-priority work (background transitions).

**Fiber node** — a plain JS object representing one unit of work. Each component/element maps to a fiber. Key fields:
```
{
  type,           // component function or DOM tag string
  stateNode,      // DOM node or class instance
  return,         // parent fiber
  child,          // first child fiber
  sibling,        // next sibling fiber
  alternate,      // previous version (double-buffer)
  lanes,          // bitmask of pending work (replaces old expiration time)
  flags,          // what mutations are needed (Placement, Update, Deletion)
  memoizedState,  // hook list (linked list of { memoizedState, queue, next })
}
```

**Two-phase execution:**

*Render phase* (interruptible) — React traverses the fiber tree, calling function components, running hooks, diffing output. No side effects. Can be paused, abandoned, or restarted. React 18 uses `MessageChannel` to yield to the browser after each 5ms slice.

*Commit phase* (synchronous, non-interruptible) — React applies all queued DOM mutations in a single synchronous pass. Three sub-phases: `beforeMutation` (reads layout), `mutation` (applies DOM changes), `layout` (runs `useLayoutEffect` cleanups + effects). `useEffect` is scheduled asynchronously after paint.

```typescript
// How hooks are stored — a linked list on the fiber
// Each useState / useEffect / useCallback / useMemo is one node:
//
// fiber.memoizedState → { memoizedState: 0, queue: {...}, next →
//                        { memoizedState: false, queue: {...}, next →
//                          null }}
//
// This is why hooks must always be called in the same order — React
// identifies each hook by its position in the list, not by name.

// startTransition marks work as non-urgent (TransitionLane)
// React can interrupt it to handle urgent input
import { useTransition, useState } from 'react';

function SearchPage({ allItems }: { allItems: string[] }) {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState(allItems);
  const [isPending, startTransition] = useTransition();

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setQuery(e.target.value); // urgent: InputContinuousLane
    startTransition(() => {
      // non-urgent: TransitionLane — render phase work can be interrupted
      setResults(allItems.filter(i => i.includes(e.target.value)));
    });
  };

  return (
    <>
      <input value={query} onChange={handleChange} />
      {isPending && <span>Updating…</span>}
      <ul>{results.map(r => <li key={r}>{r}</li>)}</ul>
    </>
  );
}
```

**Common interview trap:** Describing Fiber as "just virtual DOM diffing." Fiber's key contribution is that the render phase is **interruptible** — it can be paused between fibers and resumed later, which was impossible with the stack-based algorithm. Also: the Scheduler uses `MessageChannel`, not `requestIdleCallback` — `requestIdleCallback` fires only when the browser is idle, but React needs to maintain responsiveness even under load, so it schedules its own 5ms slices via `MessageChannel`.

answer.ru:
### Архитектура React Fiber

Fiber — полная переработка алгоритма согласования React (React 16+). Ключевая идея: рендеринг должен быть **прерываемым**, чтобы высокоприоритетные обновления (ввод пользователя) могли вытеснять низкоприоритетную работу (фоновые переходы).

**Fiber-узел** — обычный JS-объект, представляющий одну единицу работы. Каждый компонент/элемент соответствует fiber. Ключевые поля:
```
{
  type,           // функция компонента или строка DOM-тега
  stateNode,      // DOM-узел или экземпляр класса
  return,         // родительский fiber
  child,          // первый дочерний fiber
  sibling,        // следующий sibling fiber
  alternate,      // предыдущая версия (двойная буферизация)
  lanes,          // битовая маска ожидающей работы
  flags,          // нужные мутации (Placement, Update, Deletion)
  memoizedState,  // список хуков (связный список { memoizedState, queue, next })
}
```

**Двухфазное выполнение:**

*Render phase* (прерываемая) — React обходит дерево fiber, вызывает функции компонентов, запускает хуки, diff-ит вывод. Нет побочных эффектов. Может быть приостановлена, отменена или перезапущена. React 18 использует `MessageChannel` для уступки браузеру после каждых 5 мс.

*Commit phase* (синхронная, непрерываемая) — React применяет все накопленные DOM-мутации за один синхронный проход. Три подфазы: `beforeMutation` (чтение layout), `mutation` (применение DOM-изменений), `layout` (запуск cleanup и эффектов `useLayoutEffect`). `useEffect` планируется асинхронно после paint.

```typescript
// Как хуки хранятся — связный список на fiber
// Каждый useState / useEffect / useCallback / useMemo — один узел:
//
// fiber.memoizedState → { memoizedState: 0, queue: {...}, next →
//                        { memoizedState: false, queue: {...}, next →
//                          null }}
//
// Именно поэтому хуки должны вызываться в одном порядке — React
// идентифицирует каждый хук по позиции в списке, а не по имени.

import { useTransition, useState } from 'react';

function SearchPage({ allItems }: { allItems: string[] }) {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState(allItems);
  const [isPending, startTransition] = useTransition();

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setQuery(e.target.value); // срочно: InputContinuousLane
    startTransition(() => {
      // несрочно: TransitionLane — работа render phase может быть прервана
      setResults(allItems.filter(i => i.includes(e.target.value)));
    });
  };

  return (
    <>
      <input value={query} onChange={handleChange} />
      {isPending && <span>Обновление…</span>}
      <ul>{results.map(r => <li key={r}>{r}</li>)}</ul>
    </>
  );
}
```

**Типичная ошибка на интервью:** Описывать Fiber как «просто diff виртуального DOM». Ключевой вклад Fiber — render phase **прерываема**: её можно приостановить между fiber-узлами и возобновить позже, что было невозможно со стековым алгоритмом. Также: Scheduler использует `MessageChannel`, а не `requestIdleCallback` — последний срабатывает только когда браузер простаивает, а React должен обеспечивать отзывчивость даже под нагрузкой, поэтому планирует свои 5-мс срезы через `MessageChannel`.

answer.en:
### Stale Closures in Hooks

A stale closure captures old state/prop values when dependencies are missing or incorrect. When the callback executes later, it references outdated values instead of current ones. This commonly occurs with useCallback when dependencies aren't included.

```typescript
function Counter() {
  const [count, setCount] = useState(0);
  const handleClick = useCallback(() => {
    console.log(count); // Always logs 0 if count not in deps
  }, []); // Missing count dependency!
  return <button onClick={handleClick}>{count}</button>;
}
```

**Common interview trap:** Thinking stale closures only affect useCallback—useEffect and event handlers suffer the same issue when dependencies are missing.

answer.ru:
### Устаревшие Closures в Hooks

Устаревший closure захватывает старые значения состояния/props, когда зависимости отсутствуют или неправильные. Когда callback выполняется позже, он ссылается на устаревшие значения вместо текущих. Это обычно происходит с useCallback, когда зависимости не указаны.

```typescript
function Counter() {
  const [count, setCount] = useState(0);
  const handleClick = useCallback(() => {
    console.log(count); // Всегда логирует 0, если count не в зависимостях
  }, []); // Отсутствует зависимость count!
  return <button onClick={handleClick}>{count}</button>;
}
```

**Типичная ошибка:** Думать, что устаревшие closures влияют только на useCallback—useEffect и обработчики событий страдают от той же проблемы.

answer.en:
### useTransition vs useDeferredValue

useTransition wraps an action that triggers state updates with lower priority, giving you a pending state. useDeferredValue delays updating a value itself without controlling the action. Use useTransition for user interactions (form submissions, sorting), useDeferredValue for derived state (search results filtering).

```typescript
// useTransition: wrap the state setter
const [isPending, startTransition] = useTransition();
const handleSort = () => startTransition(() => setSortBy(newSort));

// useDeferredValue: defer the value itself
const deferredQuery = useDeferredValue(searchQuery);
const results = useMemo(() => filterData(deferredQuery), [deferredQuery]);
```

**Common interview trap:** Thinking they do the same thing—useTransition is action-focused, useDeferredValue is value-focused.

answer.ru:
### useTransition vs useDeferredValue

useTransition оборачивает действие, которое инициирует обновления состояния с более низким приоритетом, давая вам состояние ожидания. useDeferredValue отсрочивает обновление самого значения без управления действием. Используйте useTransition для взаимодействия пользователя (отправка форм, сортировка), useDeferredValue для производного состояния (фильтрация результатов поиска).

```typescript
// useTransition: оберните setter состояния
const [isPending, startTransition] = useTransition();
const handleSort = () => startTransition(() => setSortBy(newSort));

// useDeferredValue: отсрочьте само значение
const deferredQuery = useDeferredValue(searchQuery);
const results = useMemo(() => filterData(deferredQuery), [deferredQuery]);
```

**Типичная ошибка:** Думать, что они делают одно и то же—useTransition ориентирован на действия, useDeferredValue ориентирован на значения.

answer.en:
### Key Prop and Reconciliation

Keys tell React which elements have identity across renders, enabling element reuse and preserving internal state. Without keys, React matches by position; with keys, it matches by identity. Unstable keys (array index, Math.random()) cause state loss and performance issues because React can't reliably track elements.

```typescript
// Bad: array index as key
{list.map((item, index) => <Item key={index} value={item} />)}

// Good: stable unique identifier
{list.map(item => <Item key={item.id} value={item} />)}

// Reused element keeps its state because key is stable
```

**Common interview trap:** Thinking keys improve render performance—they actually prevent bugs when lists reorder; performance impact is usually minimal.

answer.ru:
### Ключ Key и Reconciliation

Ключи сообщают React, какие элементы имеют идентичность между рендерами, позволяя переиспользовать элементы и сохранять внутреннее состояние. Без ключей React сопоставляет по позиции; с ключами—по идентичности. Нестабильные ключи (индекс массива, Math.random()) вызывают потерю состояния и проблемы производительности, потому что React не может надежно отслеживать элементы.

```typescript
// Плохо: индекс массива как key
{list.map((item, index) => <Item key={index} value={item} />)}

// Хорошо: стабильный уникальный идентификатор
{list.map(item => <Item key={item.id} value={item} />)}

// Переиспользуемый элемент сохраняет свое состояние, потому что key стабилен
```

**Типичная ошибка:** Думать, что ключи улучшают производительность рендеринга—они на самом деле предотвращают ошибки при переупорядочении списков; влияние на производительность обычно минимально.

answer.en:
### React 18 Automatic Batching

In React 17 and earlier, batching only worked inside synchronous React event handlers. `setTimeout`, `Promise.then`, and native event listeners each triggered a separate render per `setState`.

React 18 **automatic batching** extends this to *all* update sources — async callbacks, Promises, `setTimeout`, native events — so multiple `setState` calls in any of these contexts are batched into a single render.

```typescript
import { useState, useEffect } from 'react';
import { flushSync } from 'react-dom';

function DataLoader() {
  const [data, setData] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchData = async () => {
    // React 18: ALL three updates batched → single re-render
    setLoading(true);
    setData([]);
    setError(null);

    try {
      const result = await fetch('/api/data').then(r => r.json());
      // React 18: these two updates inside Promise.then are ALSO batched
      setData(result);
      setLoading(false);
    } catch (e) {
      setError((e as Error).message);
      setLoading(false);
    }
  };

  // When automatic batching is actively harmful:
  const fetchWithFlush = async () => {
    // Force immediate DOM update for loading indicator before the async work
    flushSync(() => setLoading(true));
    // ↑ React renders synchronously here, updating the DOM before fetch starts

    const result = await fetch('/api/data').then(r => r.json());
    setData(result);      // these two are batched
    setLoading(false);
  };

  return (
    <div>
      {loading && <p>Loading...</p>}
      {error && <p>Error: {error}</p>}
      <ul>{data.map(d => <li key={d}>{d}</li>)}</ul>
      <button onClick={fetchData}>Fetch</button>
    </div>
  );
}
```

**Common interview trap:** Claiming "async updates don't batch in React 18." This was true in React 17, but React 18 batches updates in *all* contexts — including `setTimeout`, `Promise.then`, and native DOM events. The opposite mistake: assuming `flushSync` batches across calls — it only forces a synchronous flush for the single updater function you pass to it; each `flushSync` call is independent.

answer.ru:
### Автоматический батчинг React 18

В React 17 и ранее батчинг работал только внутри синхронных обработчиков событий React. Каждый `setState` в `setTimeout`, `Promise.then` или нативных обработчиках запускал отдельный рендер.

**Автоматический батчинг** React 18 расширяет это на *все* источники обновлений — async-колбэки, Promises, `setTimeout`, нативные события — так что несколько вызовов `setState` в любом из этих контекстов объединяются в один рендер.

```typescript
import { useState, useEffect } from 'react';
import { flushSync } from 'react-dom';

function DataLoader() {
  const [data, setData] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchData = async () => {
    // React 18: ВСЕ три обновления батчируются → один перерендер
    setLoading(true);
    setData([]);
    setError(null);

    try {
      const result = await fetch('/api/data').then(r => r.json());
      // React 18: эти два обновления внутри Promise.then ТОЖЕ батчируются
      setData(result);
      setLoading(false);
    } catch (e) {
      setError((e as Error).message);
      setLoading(false);
    }
  };

  // Когда автобатчинг активно мешает:
  const fetchWithFlush = async () => {
    // Форсируем немедленное обновление DOM для индикатора загрузки до начала запроса
    flushSync(() => setLoading(true));
    // ↑ React рендерит синхронно здесь, обновляя DOM до начала fetch

    const result = await fetch('/api/data').then(r => r.json());
    setData(result);      // эти два батчируются
    setLoading(false);
  };

  return (
    <div>
      {loading && <p>Загрузка...</p>}
      {error && <p>Ошибка: {error}</p>}
      <ul>{data.map(d => <li key={d}>{d}</li>)}</ul>
      <button onClick={fetchData}>Загрузить</button>
    </div>
  );
}
```

**Типичная ошибка на интервью:** Утверждать, что «async-обновления не батчируются в React 18». Это было верно для React 17, но React 18 батчирует обновления во *всех* контекстах — включая `setTimeout`, `Promise.then` и нативные DOM-события. Обратная ошибка: считать, что `flushSync` батчирует несколько вызовов — он только форсирует синхронный сброс для одной функции-обновителя; каждый вызов `flushSync` независим.

answer.en:
### Fiber Render vs Commit Phases

The render phase is interruptible and builds a work-in-progress tree; the commit phase is synchronous and applies changes to the DOM. High-priority updates (like user input) can pause a low-priority render, discard it, and restart from scratch with the new state.

```typescript
function App() {
  const [count, setCount] = useState(0);
  const [isPending, startTransition] = useTransition();

  const handleSlowUpdate = () => {
    startTransition(() => setCount(c => c + 1)); // Low priority
  };
  return <button onClick={handleSlowUpdate}>{count}</button>;
}
```

**Common interview trap:** Assuming both phases are always interruptible—only render phase can be interrupted.

answer.ru:
### Фазы Render и Commit в Fiber

Фаза render прерываема и строит дерево work-in-progress; фаза commit синхронна и применяет изменения к DOM. Обновления высокого приоритета (например, ввод пользователя) могут приостановить низкоприоритетный рендеринг, отменить его и перезапустить с новым состоянием.

```typescript
function App() {
  const [count, setCount] = useState(0);
  const [isPending, startTransition] = useTransition();

  const handleSlowUpdate = () => {
    startTransition(() => setCount(c => c + 1)); // Low priority
  };
  return <button onClick={handleSlowUpdate}>{count}</button>;
}
```

**Типичная ошибка:** Предположение, что обе фазы всегда прерываемы—прерываема только фаза render.

answer.en:
### Stale Closures in React Hooks

A stale closure captures an outdated value from a previous render and continues using it even after state has changed. This happens because function components create a new closure on every render — if a hook's function is not recreated (due to a missing dependency), it keeps referencing the old variables.

```typescript
import { useState, useEffect, useCallback, useRef } from 'react';

// ✗ STALE: interval callback captures the initial count = 0
// Adding count to deps fixes this but causes interval to restart every second
function StaleCounter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      setCount(count + 1); // ← always reads count = 0 (stale closure)
    }, 1000);
    return () => clearInterval(id);
  }, []); // empty deps: callback never refreshes

  return <div>Count: {count}</div>; // stays at 1 forever
}

// ✓ FIX 1: functional updater — no closure over count
function FunctionalUpdaterCounter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      setCount(c => c + 1); // ← always gets the latest state, no stale closure
    }, 1000);
    return () => clearInterval(id);
  }, []); // empty deps is correct now

  return <div>Count: {count}</div>;
}

// ✓ FIX 2: ref for latest value — for cases where functional updater isn't enough
function RefCounter() {
  const [count, setCount] = useState(0);
  const countRef = useRef(count);
  countRef.current = count; // keep ref in sync with latest render

  useEffect(() => {
    const id = setInterval(() => {
      console.log('Latest count:', countRef.current); // always current
      setCount(c => c + 1);
    }, 1000);
    return () => clearInterval(id);
  }, []);

  return <div>Count: {count}</div>;
}
```

**Common interview trap:** Thinking the fix is always "add everything to the dependency array." Adding `count` to deps above would restart the interval every second, which may or may not be acceptable. The *correct* fix depends on what the effect needs: use the functional updater form (`c => c + 1`) when you only need the previous value, or a ref when you need the current value for a read (not just to derive the next state). The ESLint rule `react-hooks/exhaustive-deps` guides you toward the right choice.

answer.ru:
### Устаревшие замыкания в хуках React

Устаревшее замыкание захватывает устаревшее значение из предыдущего рендера и продолжает его использовать даже после изменения state. Это происходит потому, что функциональные компоненты создают новое замыкание при каждом рендере — если функция хука не пересоздаётся (из-за отсутствующей зависимости), она продолжает ссылаться на старые переменные.

```typescript
import { useState, useEffect, useCallback, useRef } from 'react';

// ✗ УСТАРЕВШЕЕ: интервальный callback захватывает начальный count = 0
// Добавление count в deps исправляет это, но вызывает перезапуск интервала каждую секунду
function StaleCounter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      setCount(count + 1); // ← всегда читает count = 0 (устаревшее замыкание)
    }, 1000);
    return () => clearInterval(id);
  }, []); // пустые deps: callback никогда не обновляется

  return <div>Счётчик: {count}</div>; // всегда показывает 1
}

// ✓ ИСПРАВЛЕНИЕ 1: функциональный обновитель — нет замыкания на count
function FunctionalUpdaterCounter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      setCount(c => c + 1); // ← всегда получает последний state
    }, 1000);
    return () => clearInterval(id);
  }, []); // пустые deps теперь верны

  return <div>Счётчик: {count}</div>;
}

// ✓ ИСПРАВЛЕНИЕ 2: ref для последнего значения — когда функциональный обновитель недостаточен
function RefCounter() {
  const [count, setCount] = useState(0);
  const countRef = useRef(count);
  countRef.current = count; // синхронизируем ref с последним рендером

  useEffect(() => {
    const id = setInterval(() => {
      console.log('Текущий счётчик:', countRef.current); // всегда актуален
      setCount(c => c + 1);
    }, 1000);
    return () => clearInterval(id);
  }, []);

  return <div>Счётчик: {count}</div>;
}
```

**Типичная ошибка на интервью:** Считать, что исправление — всегда «добавить всё в массив зависимостей». Добавление `count` в deps в примере выше перезапускало бы интервал каждую секунду, что может быть неприемлемо. *Правильное* исправление зависит от того, что нужно эффекту: функциональный обновитель (`c => c + 1`) когда нужно только предыдущее значение, или ref когда нужно текущее значение для чтения (а не для вывода следующего состояния). ESLint-правило `react-hooks/exhaustive-deps` помогает сделать правильный выбор.

answer.en:
### Key Prop and Reconciliation

The key prop helps React identify which items have changed, been added, or been removed. Using array indices as keys causes problems when the list reorders or items are inserted/deleted because the same DOM node gets reused with different data.

```typescript
// Bad: indices as keys
<ul>
  {items.map((item, idx) => <li key={idx}>{item.name}</li>)}
</ul>

// Good: stable unique identifier
<ul>
  {items.map(item => <li key={item.id}>{item.name}</li>)}
</ul>

// Safe with indices: static list that never reorders
<ul>
  {STATIC_ITEMS.map((item, idx) => <li key={idx}>{item}</li>)}
</ul>
```

**Common interview trap:** Assuming indices are always bad—they're safe only for static, non-reordering lists.

answer.ru:
### Prop Key и согласование

Prop key помогает React определить, какие элементы изменились, были добавлены или удалены. Использование индексов массива как ключей вызывает проблемы при переупорядочении списка или вставке/удалении элементов, потому что одна и та же DOM-узел переиспользуется с разными данными.

```typescript
// Плохо: индексы как ключи
<ul>
  {items.map((item, idx) => <li key={idx}>{item.name}</li>)}
</ul>

// Хорошо: стабильный уникальный идентификатор
<ul>
  {items.map(item => <li key={item.id}>{item.name}</li>)}
</ul>

// Безопасно с индексами: статический список без переупорядочения
<ul>
  {STATIC_ITEMS.map((item, idx) => <li key={idx}>{item}</li>)}
</ul>
```

**Типичная ошибка:** Предположение, что индексы всегда плохи—они безопасны только для статических, не переупорядочивающихся списков.

answer.en:
### useTransition vs useDeferredValue

useTransition wraps state updates to mark them as non-urgent; useDeferredValue defers a value prop. useTransition gives you isPending and startTransition, while useDeferredValue is useful for deriving values from props. Both allow concurrent features to show old UI while new content loads.

```typescript
// useTransition: for setState calls
const [isPending, startTransition] = useTransition();
startTransition(() => setQuery(text));

// useDeferredValue: for prop values
const deferredQuery = useDeferredValue(query);

// Both prevent UI blocking by keeping old content visible
return <Suspense fallback={<Skeleton/>}>
  {isPending && <Spinner/>}
  <Results query={deferredQuery} />
</Suspense>;
```

**Common interview trap:** Thinking they're interchangeable—useTransition is for actions, useDeferredValue is for values.

answer.ru:
### useTransition vs useDeferredValue

useTransition оборачивает обновления состояния, чтобы отметить их как неспешные; useDeferredValue откладывает значение prop. useTransition дает вам isPending и startTransition, а useDeferredValue полезен для вывода значений из props. Оба позволяют параллельным функциям показать старый UI во время загрузки нового контента.

```typescript
// useTransition: для вызовов setState
const [isPending, startTransition] = useTransition();
startTransition(() => setQuery(text));

// useDeferredValue: для значений prop
const deferredQuery = useDeferredValue(query);

// Оба предотвращают блокировку UI, сохраняя видимым старый контент
return <Suspense fallback={<Skeleton/>}>
  {isPending && <Spinner/>}
  <Results query={deferredQuery} />
</Suspense>;
```

**Типичная ошибка:** Думать, что они взаимозаменяемы—useTransition для действий, useDeferredValue для значений.

answer.en:
### flushSync: Forcing Synchronous Renders

`flushSync` tells React to flush all queued updates synchronously and update the DOM before the call returns. It opts out of automatic batching for the updates inside its callback. Use it sparingly — it disables batching and hurts throughput.

```typescript
import { useState, useRef } from 'react';
import { flushSync } from 'react-dom';

function InfiniteList() {
  const [items, setItems] = useState<number[]>([1, 2, 3]);
  const listRef = useRef<HTMLUListElement>(null);

  const addAndScrollToBottom = () => {
    // Without flushSync: React batches this with other updates.
    // Scrolling after setItems doesn't scroll to the new item because
    // the DOM hasn't updated yet when scrollIntoView runs.
    //
    // With flushSync: React renders synchronously, so the DOM has the
    // new <li> in it before the next line executes.
    flushSync(() => {
      setItems(prev => [...prev, prev.length + 1]);
    });
    // ✓ DOM is already updated here — scroll to the newly added item
    const list = listRef.current;
    if (list) list.lastElementChild?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <>
      <ul ref={listRef} style={{ height: 200, overflowY: 'auto' }}>
        {items.map(i => <li key={i} style={{ padding: 8 }}>Item {i}</li>)}
      </ul>
      <button onClick={addAndScrollToBottom}>Add & scroll</button>
    </>
  );
}

// Another valid use: force a specific render before measuring layout
function MeasuredBox({ content }: { content: string }) {
  const boxRef = useRef<HTMLDivElement>(null);
  const [height, setHeight] = useState(0);

  const measureAfterUpdate = (newContent: string) => {
    flushSync(() => {
      // we'd set content here — force DOM update first
    });
    // Now read layout — getBoundingClientRect reflects the updated DOM
    if (boxRef.current) setHeight(boxRef.current.getBoundingClientRect().height);
  };

  return <div ref={boxRef}>{content} (height: {height}px)</div>;
}
```

**Common interview trap:** Reaching for `flushSync` in `useEffect` — this is almost always wrong, because `useEffect` already runs after the DOM has painted. `flushSync` is the right tool only when you must *read the DOM* immediately after a state update in the same synchronous call. Overusing it removes React's batching optimization and can cause layout thrash. Prefer `useLayoutEffect` for post-DOM measurements.

answer.ru:
### flushSync: принудительные синхронные рендеры

`flushSync` заставляет React немедленно сбросить все накопленные обновления и обновить DOM до возврата из вызова. Это отключает автоматический батчинг для обновлений внутри его callback. Используйте осторожно — отключает батчинг и снижает производительность.

```typescript
import { useState, useRef } from 'react';
import { flushSync } from 'react-dom';

function InfiniteList() {
  const [items, setItems] = useState<number[]>([1, 2, 3]);
  const listRef = useRef<HTMLUListElement>(null);

  const addAndScrollToBottom = () => {
    // Без flushSync: React батчирует это с другими обновлениями.
    // Прокрутка после setItems не добирается до нового элемента, потому что
    // DOM ещё не обновлён когда вызывается scrollIntoView.
    //
    // С flushSync: React рендерит синхронно, и DOM содержит
    // новый <li> до выполнения следующей строки.
    flushSync(() => {
      setItems(prev => [...prev, prev.length + 1]);
    });
    // ✓ DOM уже обновлён здесь — прокручиваем к только что добавленному элементу
    const list = listRef.current;
    if (list) list.lastElementChild?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <>
      <ul ref={listRef} style={{ height: 200, overflowY: 'auto' }}>
        {items.map(i => <li key={i} style={{ padding: 8 }}>Элемент {i}</li>)}
      </ul>
      <button onClick={addAndScrollToBottom}>Добавить и прокрутить</button>
    </>
  );
}
```

**Типичная ошибка на интервью:** Использовать `flushSync` внутри `useEffect` — почти всегда неверно, потому что `useEffect` и так запускается после того, как DOM отрисован. `flushSync` нужен только когда необходимо *прочитать DOM* сразу после обновления state в том же синхронном вызове. Чрезмерное использование убирает оптимизацию батчинга React и может вызвать layout thrash. Для измерений DOM после рендера предпочтите `useLayoutEffect`.

answer.en:
### React Fiber and Scheduler Internals

The Fiber architecture achieves interruptible rendering by representing work as a linked list of plain objects (fibers) rather than a call stack. React traverses this tree with a work loop that can yield control to the browser between fiber nodes.

**Work loop structure:**
```typescript
// Simplified mental model of React's work loop (src/react-reconciler)
function workLoopConcurrent() {
  while (workInProgress !== null && !shouldYield()) {
    performUnitOfWork(workInProgress);
  }
}

function shouldYield(): boolean {
  // React's Scheduler asks: has 5ms elapsed since we last yielded?
  return getCurrentTime() >= deadline;
}

// Scheduler uses MessageChannel to schedule the next chunk of work
// MessageChannel fires BEFORE setTimeout(fn, 0) but AFTER paint
const channel = new MessageChannel();
channel.port1.onmessage = performWorkUntilDeadline;
function scheduleWork() {
  channel.port2.postMessage(null);
}
```

**Double-buffering — how React avoids tearing:**
React maintains two fiber trees: `current` (what's on screen) and `workInProgress` (what's being built). Mutations happen on the `workInProgress` tree; when the commit phase finishes, React swaps the root pointer. The `alternate` field on each fiber links the two trees.

**Effect tracking — how the commit phase knows what to do:**
During the render phase, React collects fiber nodes with mutations into an **effect list** (or walks `subtreeFlags` in newer versions). The commit phase iterates this list and applies DOM mutations, runs `useLayoutEffect`, then schedules `useEffect` asynchronously after paint.

```typescript
// useLayoutEffect runs in the commit phase, BEFORE paint
// useEffect runs AFTER paint (scheduled via MessageChannel)
import { useLayoutEffect, useEffect, useRef } from 'react';

function MeasuredComponent() {
  const ref = useRef<HTMLDivElement>(null);

  useLayoutEffect(() => {
    // DOM is mutated, layout is calculated, but browser hasn't painted yet
    // Safe to read layout and do synchronous DOM writes here
    const height = ref.current?.getBoundingClientRect().height;
    console.log('Height before paint:', height);
  });

  useEffect(() => {
    // Browser has painted — safe to start subscriptions, fetch data, etc.
    console.log('After paint');
  });

  return <div ref={ref}>Content</div>;
}
```

**Common interview trap:** Saying React uses `requestIdleCallback`. React's Scheduler package implements its own time-slicing via `MessageChannel` because `requestIdleCallback` only fires when the browser is idle, which would starve high-priority work. The Scheduler maintains priority queues and posts tasks via `MessageChannel.port2.postMessage`, which fires asynchronously but before the next paint, giving React control over scheduling priority.

answer.ru:
### Внутренности Fiber и Scheduler

Архитектура Fiber обеспечивает прерываемый рендеринг, представляя работу как связный список простых объектов (fiber), а не как стек вызовов. React обходит это дерево с помощью рабочего цикла, который может уступать управление браузеру между узлами fiber.

**Структура рабочего цикла:**
```typescript
// Упрощённая ментальная модель рабочего цикла React (src/react-reconciler)
function workLoopConcurrent() {
  while (workInProgress !== null && !shouldYield()) {
    performUnitOfWork(workInProgress);
  }
}

function shouldYield(): boolean {
  // Scheduler React спрашивает: прошло ли 5 мс с последней уступки?
  return getCurrentTime() >= deadline;
}

// Scheduler использует MessageChannel для планирования следующего чанка работы
// MessageChannel срабатывает ДО setTimeout(fn, 0) но ПОСЛЕ paint
const channel = new MessageChannel();
channel.port1.onmessage = performWorkUntilDeadline;
function scheduleWork() {
  channel.port2.postMessage(null);
}
```

**Двойная буферизация — как React избегает разрывов:**
React поддерживает два дерева fiber: `current` (что на экране) и `workInProgress` (что строится). Мутации происходят в дереве `workInProgress`; когда commit phase завершается, React меняет корневой указатель. Поле `alternate` каждого fiber связывает два дерева.

**Отслеживание эффектов — как commit phase знает что делать:**
Во время render phase React собирает fiber-узлы с мутациями в список эффектов (или обходит `subtreeFlags` в новых версиях). Commit phase итерирует этот список, применяет DOM-мутации, запускает `useLayoutEffect`, затем планирует `useEffect` асинхронно после paint.

```typescript
// useLayoutEffect запускается в commit phase, ДО paint
// useEffect запускается ПОСЛЕ paint (планируется через MessageChannel)
import { useLayoutEffect, useEffect, useRef } from 'react';

function MeasuredComponent() {
  const ref = useRef<HTMLDivElement>(null);

  useLayoutEffect(() => {
    // DOM мутирован, layout вычислен, но браузер ещё не отрисовал
    // Безопасно читать layout и делать синхронные DOM-записи
    const height = ref.current?.getBoundingClientRect().height;
    console.log('Высота до paint:', height);
  });

  useEffect(() => {
    // Браузер отрисовал — безопасно запускать подписки, fetch и т.д.
    console.log('После paint');
  });

  return <div ref={ref}>Контент</div>;
}
```

**Типичная ошибка на интервью:** Говорить, что React использует `requestIdleCallback`. Пакет Scheduler React реализует собственное time-slicing через `MessageChannel`, потому что `requestIdleCallback` срабатывает только когда браузер простаивает, что ставило бы высокоприоритетную работу в голодный режим. Scheduler поддерживает очереди приоритетов и размещает задачи через `MessageChannel.port2.postMessage`, что срабатывает асинхронно, но до следующего paint.

answer.en:
### Concurrent Features Comparison

useTransition wraps state setters to mark updates as non-urgent and prevents premature state commits. useDeferredValue defers a value itself without state control, useful when you receive props that need debouncing. Use useTransition for controlled actions (form input), useDeferredValue for external prop changes.

```typescript
// useTransition: control the state setter
const [isPending, startTransition] = useTransition();
startTransition(() => setQuery(input));

// useDeferredValue: defer received prop
const deferredQuery = useDeferredValue(query);
```

**Common interview trap:** Thinking they do the same thing—useTransition controls state updates, useDeferredValue defers prop values.

answer.ru:
### Сравнение Concurrent Features

useTransition оборачивает state setters для отметки обновлений как неспешные и предотвращает преждевременное коммитирование состояния. useDeferredValue отложно обновляет само значение без контроля состояния, полезно при получении props, требующих дебаунса. Используйте useTransition для контролируемых действий (ввод формы), useDeferredValue для внешних изменений props.

```typescript
// useTransition: контролирует setter состояния
const [isPending, startTransition] = useTransition();
startTransition(() => setQuery(input));

// useDeferredValue: откладывает полученное значение
const deferredQuery = useDeferredValue(query);
```

**Типичная ошибка:** Думать, что они делают одно и то же—useTransition контролирует обновления состояния, useDeferredValue откладывает значения props.

answer.en:
### Stale Closures

Stale closures occur when a hook captures an old value because dependencies are missing or incorrect. The callback "remembers" the old state and uses it instead of the fresh value. Fix by adding all used values to the dependency array.

```typescript
// BUG: stale closure
const [count, setCount] = useState(0);
useEffect(() => {
  const timer = setInterval(() => console.log(count), 1000);
  return () => clearInterval(timer);
}, []); // Missing 'count' dependency

// FIX: add dependency
useEffect(() => {
  const timer = setInterval(() => console.log(count), 1000);
  return () => clearInterval(timer);
}, [count]);
```

**Common interview trap:** Confusing dependency issues with scope—stale closures happen because JavaScript closures capture variables by reference.

answer.ru:
### Устаревшие Замыкания

Устаревшие замыкания возникают, когда hook захватывает старое значение из-за отсутствия или неправильности зависимостей. Callback "помнит" старое состояние и использует его вместо свежего значения. Исправьте, добавив все используемые значения в массив зависимостей.

```typescript
// БАГ: устаревшее замыкание
const [count, setCount] = useState(0);
useEffect(() => {
  const timer = setInterval(() => console.log(count), 1000);
  return () => clearInterval(timer);
}, []); // Отсутствует зависимость 'count'

// ИСПРАВЛЕНИЕ: добавить зависимость
useEffect(() => {
  const timer = setInterval(() => console.log(count), 1000);
  return () => clearInterval(timer);
}, [count]);
```

**Типичная ошибка:** Путать проблемы зависимостей с областью видимости—устаревшие замыкания происходят, потому что JavaScript замыкания захватывают переменные по ссылке.

answer.en:
### Context Re-render Optimization

Context re-renders all consumers when its value changes, even if only one field changed. Optimize by splitting contexts by update frequency, memoizing context value with useMemo, or extracting stable parts. Use multiple contexts instead of one monolithic context holding all state.

```typescript
// BAD: all consumers re-render on any state change
const AppContext = createContext();
<AppContext.Provider value={{ user, theme, notifications }}>

// GOOD: split by frequency
const UserContext = createContext();
const ThemeContext = createContext();
<UserContext.Provider value={useMemo(() => user, [user])}>
```

**Common interview trap:** Thinking Context is inherently slow—it's not; the issue is re-rendering too many consumers unnecessarily.

answer.ru:
### Оптимизация переренедеров Context

Context вызывает переренедер всех потребителей при изменении его значения, даже если изменилось только одно поле. Оптимизируйте, разделив contexts по частоте обновления, мемоизировав значение context с useMemo или извлекая стабильные части. Используйте несколько contexts вместо одного монолитного.

```typescript
// ПЛОХО: все потребители переренедеряются при любом изменении состояния
const AppContext = createContext();
<AppContext.Provider value={{ user, theme, notifications }}>

// ХОРОШО: разделить по частоте
const UserContext = createContext();
const ThemeContext = createContext();
<UserContext.Provider value={useMemo(() => user, [user])}>
```

**Типичная ошибка:** Думать, что Context изначально медленный—это не так; проблема в ненужном переренедере множества потребителей.

answer.en:
### Key Prop Reconciliation

The key prop tells React which elements remain the same across renders, enabling correct state preservation and DOM reuse. Without stable keys or using index as key, React mismatches elements when lists reorder, causing state leaks and animation bugs. Use unique, stable identifiers from data.

```typescript
// BAD: index as key causes state mismatch
list.map((item, index) => <Input key={index} value={item} />)

// GOOD: use stable id
list.map(item => <Input key={item.id} value={item} />)

// PROBLEM: reordering causes state confusion
// [A, B, C] -> [B, C, A] with index keys swaps state
```

**Common interview trap:** Thinking keys are only about performance—they're actually critical for correct behavioral state preservation.

answer.ru:
### Согласование Key Prop

Key prop говорит React, какие элементы остаются одинаковыми между переренедерами, позволяя правильно сохранять состояние и переиспользовать DOM. Без стабильных ключей или использования индекса как ключа, React неправильно сопоставляет элементы при переупорядочении списков, вызывая утечку состояния и баги анимации. Используйте уникальные стабильные идентификаторы из данных.

```typescript
// ПЛОХО: индекс как ключ вызывает несовпадение состояния
list.map((item, index) => <Input key={index} value={item} />)

// ХОРОШО: используйте стабильный id
list.map(item => <Input key={item.id} value={item} />)

// ПРОБЛЕМА: переупорядочение вызывает путаницу состояния
// [A, B, C] -> [B, C, A] с index ключами меняет состояние
```

**Типичная ошибка:** Думать, что ключи нужны только для производительности—они критичны для правильного сохранения поведенческого состояния.

answer.en:
### React Scheduler and Time-Slicing

React's Scheduler (separate package: `scheduler`) is a cooperative multitasking system. Work is divided into tasks; each task runs until either it finishes or the scheduler decides to yield. The scheduler does NOT use `requestIdleCallback` — it uses `MessageChannel` for precise, sub-frame task scheduling.

**Why MessageChannel, not requestIdleCallback:**
- `requestIdleCallback` fires only during browser idle periods → starves high-priority React work during busy frames
- `MessageChannel.port2.postMessage(null)` fires asynchronously *before* the next paint — giving React control between frames without waiting for the browser to be idle

**Priority levels in Scheduler:**

| Priority | Timeout | Examples |
|---|---|---|
| ImmediatePriority | -1 (synchronous) | flushSync |
| UserBlockingPriority | 250ms | click, input |
| NormalPriority | 5000ms | default transitions |
| LowPriority | 10000ms | analytics |
| IdlePriority | never expires | background prerender |

```typescript
import { useState, useTransition, useDeferredValue } from 'react';

// useTransition: opt-in to non-urgent lane
function Search({ items }: { items: string[] }) {
  const [query, setQuery] = useState('');
  const [filtered, setFiltered] = useState(items);
  const [isPending, startTransition] = useTransition();

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setQuery(e.target.value);  // urgent: InputContinuousLane — updates immediately
    startTransition(() => {
      // Non-urgent: TransitionLane — can be interrupted by new input
      setFiltered(items.filter(i => i.includes(e.target.value)));
    });
  };

  return (
    <>
      <input value={query} onChange={handleChange} />
      {isPending && <span style={{ opacity: 0.5 }}>Filtering…</span>}
      <ul>{filtered.map(i => <li key={i}>{i}</li>)}</ul>
    </>
  );
}

// useDeferredValue: defer a value (no explicit startTransition call needed)
function DeferredSearch({ items }: { items: string[] }) {
  const [query, setQuery] = useState('');
  const deferredQuery = useDeferredValue(query); // lags behind query on slow renders

  const filtered = items.filter(i => i.includes(deferredQuery));
  const isStale = query !== deferredQuery;

  return (
    <>
      <input value={query} onChange={e => setQuery(e.target.value)} />
      <div style={{ opacity: isStale ? 0.5 : 1 }}>
        {filtered.map(i => <li key={i}>{i}</li>)}
      </div>
    </>
  );
}
```

**Common interview trap:** Confusing `useDeferredValue` with `useTransition`. Both defer non-urgent work, but differ in ownership: `useTransition` wraps the *setter* (you control when the update is non-urgent), while `useDeferredValue` wraps the *value* (useful when you don't own the state setter — e.g., it comes from a parent prop). Neither substitutes for `React.memo` — deferral only helps if the rendering that consumes the value is actually memoized and skips when the deferred value is the same.

answer.ru:
### React Scheduler и Time-Slicing

React Scheduler (отдельный пакет: `scheduler`) — кооперативная система многозадачности. Работа делится на задачи; каждая выполняется пока не завершится или планировщик не решит уступить. Scheduler НЕ использует `requestIdleCallback` — он использует `MessageChannel` для точного планирования задач внутри фрейма.

**Почему MessageChannel, а не requestIdleCallback:**
- `requestIdleCallback` срабатывает только в периоды простоя браузера → голодает высокоприоритетная работа React во время занятых фреймов
- `MessageChannel.port2.postMessage(null)` срабатывает асинхронно *перед* следующим paint — даёт React контроль между фреймами без ожидания простоя

**Уровни приоритета в Scheduler:**

| Приоритет | Таймаут | Примеры |
|---|---|---|
| ImmediatePriority | -1 (синхронно) | flushSync |
| UserBlockingPriority | 250мс | клик, ввод |
| NormalPriority | 5000мс | обычные переходы |
| LowPriority | 10000мс | аналитика |
| IdlePriority | не истекает | фоновый пре-рендер |

```typescript
import { useState, useTransition, useDeferredValue } from 'react';

// useTransition: явный переход в несрочный lane
function Search({ items }: { items: string[] }) {
  const [query, setQuery] = useState('');
  const [filtered, setFiltered] = useState(items);
  const [isPending, startTransition] = useTransition();

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setQuery(e.target.value);  // срочно: InputContinuousLane — обновляется немедленно
    startTransition(() => {
      // Несрочно: TransitionLane — может быть прервано новым вводом
      setFiltered(items.filter(i => i.includes(e.target.value)));
    });
  };

  return (
    <>
      <input value={query} onChange={handleChange} />
      {isPending && <span style={{ opacity: 0.5 }}>Фильтрация…</span>}
      <ul>{filtered.map(i => <li key={i}>{i}</li>)}</ul>
    </>
  );
}

// useDeferredValue: отложить значение (без явного startTransition)
function DeferredSearch({ items }: { items: string[] }) {
  const [query, setQuery] = useState('');
  const deferredQuery = useDeferredValue(query); // отстаёт от query при медленных рендерах

  const filtered = items.filter(i => i.includes(deferredQuery));
  const isStale = query !== deferredQuery;

  return (
    <>
      <input value={query} onChange={e => setQuery(e.target.value)} />
      <div style={{ opacity: isStale ? 0.5 : 1 }}>
        {filtered.map(i => <li key={i}>{i}</li>)}
      </div>
    </>
  );
}
```

**Типичная ошибка на интервью:** Путать `useDeferredValue` с `useTransition`. Оба откладывают несрочную работу, но различаются владением: `useTransition` оборачивает *сеттер* (вы контролируете когда обновление несрочно), а `useDeferredValue` оборачивает *значение* (полезно когда вы не владеете сеттером — например, он приходит из пропса родителя). Ни один не заменяет `React.memo` — отложенность помогает только если рендер, потребляющий значение, действительно мемоизирован и пропускается когда отложенное значение то же самое.

answer.en:
### Stale Closures in Hooks

Stale closures occur when a hook captures old state/props values in its closure and uses them after they've updated. Without proper dependencies, setInterval or event handlers use outdated values from the closure.

```typescript
function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      console.log(count); // stale closure: always logs 0
    }, 1000);
    return () => clearInterval(interval);
  }, []); // missing count dependency
}
```

**Common interview trap:** Confusing stale closures with stale state—they're related but stale closures are about captured values in function scope.

answer.ru:
### Stale Closures в Hooks

Stale closures возникают, когда hook захватывает старые значения state/props в своем замыкании и использует их после обновления. Без правильных dependencies, setInterval или обработчики событий используют устаревшие значения из замыкания.

```typescript
function Counter() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      console.log(count); // stale closure: всегда логирует 0
    }, 1000);
    return () => clearInterval(interval);
  }, []); // missing count dependency
}
```

**Типичная ошибка:** Путать stale closures со stale state—они связаны, но stale closures о захваченных значениях в scope функции.

answer.en:
### Key Prop in Reconciliation

The key prop tells React which DOM node corresponds to which component instance across re-renders. Without unique keys, React reuses DOM nodes and component state incorrectly, causing form state to leak between items and breaking Suspense boundaries.

```typescript
// Bad: index as key (breaks on reorder)
{items.map((item, index) => <Item key={index} {...item} />)}

// Good: stable unique identifier
{items.map((item) => <Item key={item.id} {...item} />)}

// With Suspense, bad keys cause state to persist across suspending items
{items.map(item => <Suspense key={item.id}><Async id={item.id} /></Suspense>)}
```

**Common interview trap:** Thinking keys are only for performance—they affect correctness of state and behavior.

answer.ru:
### Key Prop при согласовании

Key prop говорит React, какой DOM ноде соответствует какой экземпляр компонента между re-renders. Без уникальных keys, React неправильно переиспользует DOM ноды и состояние компонента, вызывая утечку состояния формы между элементами и нарушая Suspense boundaries.

```typescript
// Плохо: index как key (ломается при переупорядочении)
{items.map((item, index) => <Item key={index} {...item} />)}

// Хорошо: стабильный уникальный идентификатор
{items.map((item) => <Item key={item.id} {...item} />)}

// С Suspense, плохие keys вызывают сохранение состояния в suspending items
{items.map(item => <Suspense key={item.id}><Async id={item.id} /></Suspense>)}
```

**Типичная ошибка:** Думать, что keys только для performance—они влияют на корректность состояния и поведения.

answer.en:
### React Server Components vs SSR

Server-Side Rendering (SSR) and React Server Components (RSC) both run React on the server, but they do fundamentally different things:

- **SSR** renders components to HTML strings on the server. The client then downloads JS and **hydrates** — attaching React event handlers to the existing HTML. All components eventually become interactive client-side.
- **RSC** sends a serialized React component tree (not HTML). RSC code **never ships to the client**. They can `await` data fetching directly in the component body. Only Client Components (marked `'use client'`) are hydrated.

```typescript
// Server Component — runs only on server, zero JS sent to client
// No hooks, no event handlers — but can directly await data
async function UserProfile({ userId }: { userId: string }) {
  // Safe parameterized query — never put user input directly in SQL
  const user = await db.query(
    'SELECT id, name, bio FROM users WHERE id = $1',
    [userId]   // parameterized — prevents SQL injection
  );

  return (
    <article>
      <h1>{user.name}</h1>
      <p>{user.bio}</p>
      {/* Client Component embedded in server tree — only this part is hydrated */}
      <FollowButton userId={userId} />
    </article>
  );
}

// Client Component — hydrated on client, can use hooks/events
'use client';
function FollowButton({ userId }: { userId: string }) {
  const [following, setFollowing] = useState(false);
  return (
    <button onClick={() => setFollowing(f => !f)}>
      {following ? 'Unfollow' : 'Follow'}
    </button>
  );
}
```

**Key differences summary:**

| | SSR | RSC |
|---|---|---|
| Output | HTML string | Serialized component tree |
| Client JS | Full component bundle | Only Client Components |
| Data fetching | `getServerSideProps` / loaders | Direct `await` in component |
| Hooks | After hydration | Never (server-only) |

**Common interview trap:** Thinking RSC replaces SSR — they complement each other. Next.js App Router uses both: RSC for the component tree, SSR to render that tree to initial HTML for fast first paint. RSC's benefit is **bundle size** — server-only code (database clients, heavy parsers) never reaches the browser.

answer.ru:
### React Server Components vs SSR

Server-Side Rendering (SSR) и React Server Components (RSC) оба запускают React на сервере, но делают принципиально разные вещи:

- **SSR** рендерит компоненты в HTML-строки на сервере. Клиент загружает JS и **гидрирует** — прикрепляет обработчики событий React к существующему HTML. Все компоненты в конечном счёте становятся интерактивными на клиенте.
- **RSC** отправляет сериализованное дерево компонентов React (не HTML). Код RSC **никогда не попадает на клиент**. RSC может `await` данные прямо в теле компонента. Только Client Components (помеченные `'use client'`) гидрируются.

```typescript
// Server Component — запускается только на сервере, нулевой JS на клиенте
// Нет хуков, нет обработчиков событий — но можно напрямую await данные
async function UserProfile({ userId }: { userId: string }) {
  // Безопасный параметризованный запрос — никогда не вставляйте пользовательский ввод напрямую в SQL
  const user = await db.query(
    'SELECT id, name, bio FROM users WHERE id = $1',
    [userId]   // параметризованный — предотвращает SQL-инъекцию
  );

  return (
    <article>
      <h1>{user.name}</h1>
      <p>{user.bio}</p>
      {/* Client Component внутри серверного дерева — только эта часть гидрируется */}
      <FollowButton userId={userId} />
    </article>
  );
}

// Client Component — гидрируется на клиенте, может использовать хуки/события
'use client';
function FollowButton({ userId }: { userId: string }) {
  const [following, setFollowing] = useState(false);
  return (
    <button onClick={() => setFollowing(f => !f)}>
      {following ? 'Отписаться' : 'Подписаться'}
    </button>
  );
}
```

**Ключевые различия:**

| | SSR | RSC |
|---|---|---|
| Вывод | HTML-строка | Сериализованное дерево |
| JS на клиенте | Весь бандл компонента | Только Client Components |
| Загрузка данных | `getServerSideProps` / loaders | Прямой `await` в компоненте |
| Хуки | После гидрации | Никогда (только сервер) |

**Типичная ошибка на интервью:** Считать, что RSC заменяет SSR — они дополняют друг друга. Next.js App Router использует оба: RSC для дерева компонентов, SSR для рендера этого дерева в начальный HTML для быстрого первого paint. Преимущество RSC — **размер бандла**: серверный код (клиенты БД, тяжёлые парсеры) никогда не попадает в браузер.

answer.en:
### Hydration Mismatch Debugging

Hydration mismatch occurs when server HTML differs from client render. Use React DevTools to inspect mismatches, check for date/time differences, conditional rendering based on browser APIs, or CSS-in-JS inconsistencies. Add suppressHydrationWarning cautiously only after identifying root cause.

```typescript
// Problem: new Date() differs on server vs client
export function TimeComponent() {
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);
  const time = mounted ? new Date().toLocaleString() : 'Loading...';
  return <div>{time}</div>;
}

// Better: use initial value from server
function Clock({ initialTime }: { initialTime: string }) {
  return <div>{initialTime}</div>;
}
```

**Common interview trap:** Using suppressHydrationWarning without understanding the underlying cause.

answer.ru:
### Отладка гидратационного рассогласования

Рассогласование гидратации возникает, когда серверный HTML отличается от клиентского. Используйте React DevTools для инспекции, проверьте различия в дате/времени, условный рендеринг на основе браузерных API или CSS-in-JS. suppressHydrationWarning используйте только после определения причины.

```typescript
// Проблема: new Date() различается
export function TimeComponent() {
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);
  const time = mounted ? new Date().toLocaleString() : 'Loading...';
  return <div>{time}</div>;
}

// Лучше: использовать значение с сервера
function Clock({ initialTime }: { initialTime: string }) {
  return <div>{initialTime}</div>;
}
```

**Типичная ошибка:** Использование suppressHydrationWarning без понимания корневой причины.

answer.en:
### React Lane Model

Lanes are bitmasks representing update priority. React uses concurrent rendering to interleave work based on priority. Urgent updates (like user input) interrupt lower-priority renders (like data fetching). The scheduler batches updates and uses requestAnimationFrame or MessageChannel for time-slicing.

```typescript
// startTransition wraps non-urgent updates in lower priority lanes
import { startTransition } from 'react';

function SearchComponent() {
  const [input, setInput] = useState('');
  const [results, setResults] = useState([]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInput(e.target.value); // Urgent
    startTransition(() => {
      setResults(filterResults(e.target.value)); // Non-urgent
    });
  };
}
```

**Common interview trap:** Confusing lanes with hooks priority or thinking all updates have equal priority.

answer.ru:
### Lane-модель React

Lanes — это битовые маски, представляющие приоритет обновления. React использует concurrent рендеринг для чередования работы по приоритету. Срочные обновления (вроде ввода пользователя) прерывают низкоприоритетные рендеры (вроде загрузки данных). Scheduler использует requestAnimationFrame для time-slicing.

```typescript
// startTransition оборачивает неспешные обновления в низкоприоритетные lanes
import { startTransition } from 'react';

function SearchComponent() {
  const [input, setInput] = useState('');
  const [results, setResults] = useState([]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInput(e.target.value); // Срочно
    startTransition(() => {
      setResults(filterResults(e.target.value)); // Неспешно
    });
  };
}
```

**Типичная ошибка:** Путаница между lanes и приоритетом хуков.

answer.en:
### Custom Renderers

React Core is platform-agnostic; renderers implement platform-specific logic through the reconciler interface. Renderers handle creating/updating/removing host instances (DOM nodes, native views). You can create custom renderers using createRoot and the reconciler package (react-reconciler).

```typescript
// Simplified custom renderer example
import { Reconciler } from 'react-reconciler';

const reconciler = Reconciler({
  createInstance(type, props, rootContainer) {
    return { type, props, children: [] };
  },
  appendChild(parentInstance, childInstance) {
    parentInstance.children.push(childInstance);
  },
  commitUpdate(instance, updatePayload) {
    Object.assign(instance.props, updatePayload);
  }
});
```

**Common interview trap:** Thinking React Core includes DOM logic; it doesn't.

answer.ru:
### Custom Renderers

React Core платформенно-независима; рендеры реализуют платформенно-специфичную логику через reconciler интерфейс. Рендеры обрабатывают создание/обновление/удаление host instances (DOM ноды, native views). Можно создавать custom renderers через react-reconciler.

```typescript
// Упрощенный пример custom renderer
import { Reconciler } from 'react-reconciler';

const reconciler = Reconciler({
  createInstance(type, props, rootContainer) {
    return { type, props, children: [] };
  },
  appendChild(parentInstance, childInstance) {
    parentInstance.children.push(childInstance);
  },
  commitUpdate(instance, updatePayload) {
    Object.assign(instance.props, updatePayload);
  }
});
```

**Типичная ошибка:** Думать, что React Core включает DOM логику.

answer.en:
### React Forget Compiler

React Forget automatically memoizes values and functions at compile-time, eliminating manual useMemo/useCallback. It analyzes dependencies and inserts memoization automatically. Unlike useMemo, it's invisible and runs during build; limitations include complex function analysis and current experimental status in React 19.

```typescript
// Without React Forget - manual memoization
function Component({ data }) {
  const memoizedValue = useMemo(() => expensiveCompute(data), [data]);
  const memoizedCallback = useCallback(() => handleClick(), []);
  return <Child value={memoizedValue} onClick={memoizedCallback} />;
}

// With React Forget - automatic (conceptually)
function Component({ data }) {
  const memoizedValue = expensiveCompute(data); // Auto-memoized by compiler
  const memoizedCallback = () => handleClick(); // Auto-memoized by compiler
  return <Child value={memoizedValue} onClick={memoizedCallback} />;
}
```

**Common interview trap:** Assuming React Forget replaces all useMemo immediately or works perfectly with all code patterns.

answer.ru:
### React Forget Компилятор

React Forget автоматически мемоизирует значения и функции на время компиляции, исключая ручное useMemo/useCallback. Анализирует зависимости и автоматически вставляет мемоизацию. В отличие от useMemo, он невидимый и запускается во время сборки; ограничения включают сложный анализ функций.

```typescript
// Без React Forget - ручная мемоизация
function Component({ data }) {
  const memoizedValue = useMemo(() => expensiveCompute(data), [data]);
  const memoizedCallback = useCallback(() => handleClick(), []);
  return <Child value={memoizedValue} onClick={memoizedCallback} />;
}

// С React Forget - автоматическая (концептуально)
function Component({ data }) {
  const memoizedValue = expensiveCompute(data); // Автомемоизация
  const memoizedCallback = () => handleClick(); // Автомемоизация
  return <Child value={memoizedValue} onClick={memoizedCallback} />;
}
```

**Типичная ошибка:** Предположение, что React Forget сразу заменит все useMemo.

answer.en:
### Server Components vs Traditional SSR

Server Components execute only on the server and never send their code to the client, reducing bundle size. They serialize to a special wire format instead of HTML, allowing seamless Server/Client boundaries. Traditional SSR hydrates HTML, requiring full component code client-side.

```typescript
// Server Component - never reaches client
'use server';
export default async function ServerOnly() {
  const data = await db.query();
  return <div>{data}</div>; // No JS sent
}

// Client Component needs full code
'use client';
export default function Interactive() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}
```

**Common interview trap:** Confusing Server Components with SSR—Server Components don't send HTML, they send serialized component trees.

answer.ru:
### Server Components vs традиционный SSR

Server Components выполняются только на сервере и никогда не отправляют свой код клиенту, уменьшая размер бандла. Они сериализуются в специальный wire-формат вместо HTML, позволяя бесшовно менять Server/Client границы. Традиционный SSR гидрирует HTML, требуя полного кода компонента на клиенте.

```typescript
// Server Component - не доходит до клиента
'use server';
export default async function ServerOnly() {
  const data = await db.query();
  return <div>{data}</div>; // Нет JS
}

// Client Component нужен полный код
'use client';
export default function Interactive() {
  const [count, setCount] = useState(0);
  return <button onClick={() => setCount(c => c + 1)}>{count}</button>;
}
```

**Типичная ошибка:** Путать Server Components с SSR—Server Components не отправляют HTML, они отправляют сериализованные деревья компонентов.

answer.en:
### Debugging Hydration Mismatches

Mismatches occur when server-rendered HTML differs from client-rendered output (random IDs, timestamps, browser-only APIs). Use React's built-in console warnings and add suppressHydrationWarning for known safe mismatches, or isolate client-only components with dynamic imports and ClientOnly wrappers.

```typescript
// Problem: Random values differ between server and client
export function BadComponent() {
  const id = Math.random(); // Different each render!
  return <div>{id}</div>;
}

// Solution: Suppress or use suppressHydrationWarning
export function GoodComponent() {
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  return mounted ? <div>{Math.random()}</div> : null;
}

// Alternative: suppressHydrationWarning for known safe cases
<div suppressHydrationWarning>{new Date().toISOString()}</div>
```

**Common interview trap:** Ignoring hydration warnings instead of fixing root causes—some mismatches indicate real logic errors that will cause bugs.

answer.ru:
### Отладка Hydration Мисматчей

Мисматчи происходят, когда HTML, отрендеренный на сервере, отличается от вывода на клиенте (случайные ID, временные метки, API только для браузера). Используйте встроенные предупреждения React и suppressHydrationWarning для известных безопасных мисматчей или изолируйте клиент-только компоненты через динамические импорты.

```typescript
// Проблема: Случайные значения отличаются
export function BadComponent() {
  const id = Math.random(); // Разное каждый раз!
  return <div>{id}</div>;
}

// Решение: Используйте useEffect для отложенного рендера
export function GoodComponent() {
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  return mounted ? <div>{Math.random()}</div> : null;
}

// Альтернатива: suppressHydrationWarning
<div suppressHydrationWarning>{new Date().toISOString()}</div>
```

**Типичная ошибка:** Игнорировать предупреждения вместо исправления причин—некоторые мисматчи указывают на реальные логические ошибки.

answer.en:
### Custom React Renderers

React's reconciliation engine (Fiber) is platform-agnostic. Custom renderers implement the renderer interface to target non-DOM platforms (React Native, Canvas, WebGL, VR). They handle platform-specific host instances, mutations, and scheduling while reusing React's core reconciliation logic.

```typescript
// Simplified custom renderer for console output
const ConsoleRenderer = ReactReconciler({
  createInstance(type, props) {
    return { type, props, children: [] };
  },
  appendInitialChild(parent, child) {
    parent.children.push(child);
  },
  commitUpdate(instance, updatePayload, type, oldProps, newProps) {
    instance.props = newProps;
  },
  // ... other required methods
  scheduleTimeout: setTimeout,
  cancelTimeout: clearTimeout,
});

const root = ConsoleRenderer.createRoot({});
root.render(<MyComponent />);
```

**Common interview trap:** Thinking custom renderers are just DOM abstractions—they work for any medium: native apps, VR, 3D engines, IoT devices.

answer.ru:
### Пользовательские Рендеры React

Мотор согласования React (Fiber) не зависит от платформы. Пользовательские рендеры реализуют интерфейс рендера для нестандартных платформ (React Native, Canvas, WebGL, VR). Они обрабатывают платформенные экземпляры, мутации и расписание, переиспользуя ядро согласования React.

```typescript
// Упрощённый рендер для вывода в консоль
const ConsoleRenderer = ReactReconciler({
  createInstance(type, props) {
    return { type, props, children: [] };
  },
  appendInitialChild(parent, child) {
    parent.children.push(child);
  },
  commitUpdate(instance, updatePayload, type, oldProps, newProps) {
    instance.props = newProps;
  },
  // ... остальные методы
  scheduleTimeout: setTimeout,
  cancelTimeout: clearTimeout,
});

const root = ConsoleRenderer.createRoot({});
root.render(<MyComponent />);
```

**Типичная ошибка:** Думать, что пользовательские рендеры — это просто абстракции DOM—они работают для любого носителя: нативные приложения, VR, 3D-движки, IoT.

answer.en:
### React Forget (React Compiler)

React Forget automatically memoizes component outputs and dependencies without manual useMemo/useCallback, eliminating unnecessary re-renders. It analyzes data flow to identify values that don't change and wraps them in automatic memoization, transforming components into optimized versions at compile time.

```typescript
// Before: Manual memoization required
const MyComponent = ({ userId }) => {
  const user = useMemo(() => fetchUser(userId), [userId]);
  const handleClick = useCallback(() => console.log(user), [user]);
  return <button onClick={handleClick}>Click</button>;
};

// After: React Forget automatically optimizes
const MyComponent = ({ userId }) => {
  const user = fetchUser(userId); // Automatically memoized
  const handleClick = () => console.log(user); // Automatically stable
  return <button onClick={handleClick}>Click</button>;
};
```

**Common interview trap:** Thinking React Forget replaces all performance tuning—it only handles component-level memoization; algorithmic improvements and data fetching patterns still matter.

answer.ru:
### React Forget (React Compiler)

React Forget автоматически мемоизирует выходы компонентов и зависимости без useMemo/useCallback, исключая ненужные пересчёты. Он анализирует поток данных, чтобы найти значения, которые не меняются, и оборачивает их в автоматическую мемоизацию на уровне компиляции.

```typescript
// До: Требуется ручная мемоизация
const MyComponent = ({ userId }) => {
  const user = useMemo(() => fetchUser(userId), [userId]);
  const handleClick = useCallback(() => console.log(user), [user]);
  return <button onClick={handleClick}>Click</button>;
};

// После: React Forget автоматически оптимизирует
const MyComponent = ({ userId }) => {
  const user = fetchUser(userId); // Автоматически мемоизирано
  const handleClick = () => console.log(user); // Автоматически стабильно
  return <button onClick={handleClick}>Click</button>;
};
```

**Типичная ошибка:** Думать, что React Forget заменяет всю оптимизацию производительности—он только обрабатывает мемоизацию на уровне компонента; алгоритмические улучшения остаются важны.

answer.en:
### RSC and Next.js App Router Integration

In Next.js App Router, every component is a Server Component by default. Client Components are opt-in via the `'use client'` directive. The challenge is the **composition boundary**: a Client Component cannot import a Server Component (because the server-only code would end up in the client bundle), but it *can* receive Server Components as `children` props.

```typescript
// app/posts/page.tsx — Server Component (no directive needed)
import { PostList } from '@/components/PostList';
import { LikeButton } from '@/components/LikeButton';

export default async function PostsPage() {
  // Direct DB access — safe here, never sent to client
  const posts = await db.query(
    'SELECT id, title, author_id FROM posts ORDER BY created_at DESC LIMIT 20'
    // No user input — no parameterization needed here
  );

  return (
    <main>
      <h1>Posts</h1>
      <PostList posts={posts} />
    </main>
  );
}

// components/PostList.tsx — Server Component
type Post = { id: string; title: string; author_id: string };

export async function PostList({ posts }: { posts: Post[] }) {
  return (
    <ul>
      {posts.map(post => (
        <li key={post.id}>
          <span>{post.title}</span>
          {/* LikeButton is a Client Component — only this subtree hydrates */}
          <LikeButton postId={post.id} />
        </li>
      ))}
    </ul>
  );
}

// components/LikeButton.tsx — Client Component (uses state/events)
'use client';
import { useState } from 'react';

export function LikeButton({ postId }: { postId: string }) {
  const [liked, setLiked] = useState(false);
  return (
    <button
      onClick={async () => {
        setLiked(l => !l);
        await fetch(`/api/posts/${postId}/like`, { method: 'POST' });
      }}
      aria-pressed={liked}
    >
      {liked ? '♥ Liked' : '♡ Like'}
    </button>
  );
}

// components/UserPosts.tsx — server data passed into client shell via children prop
// (the "donut" pattern: Client Component shell, Server Component content inside)
'use client';
import { useState, type ReactNode } from 'react';

export function CollapsibleSection({ children, title }: { children: ReactNode; title: string }) {
  const [open, setOpen] = useState(true);
  return (
    <section>
      <button onClick={() => setOpen(o => !o)}>{title}</button>
      {open && children}   {/* children can be Server Component output */}
    </section>
  );
}
```

**Common interview trap:** Trying to import a Server Component inside a Client Component — this pulls server-only modules (database clients, file system APIs) into the client bundle and causes a build error. The correct pattern is to pass server-rendered content *as props* (`children` or named slots) from a parent Server Component into a Client Component shell. This is the "donut" composition pattern.

answer.ru:
### RSC и интеграция с Next.js App Router

В Next.js App Router каждый компонент по умолчанию является Server Component. Client Components — opt-in через директиву `'use client'`. Сложность — в **границе композиции**: Client Component не может импортировать Server Component (иначе серверный код попал бы в клиентский бандл), но *может* получать Server Components как пропс `children`.

```typescript
// app/posts/page.tsx — Server Component (директива не нужна)
import { PostList } from '@/components/PostList';
import { LikeButton } from '@/components/LikeButton';

export default async function PostsPage() {
  // Прямой доступ к БД — безопасно, никогда не отправляется клиенту
  const posts = await db.query(
    'SELECT id, title, author_id FROM posts ORDER BY created_at DESC LIMIT 20'
    // Нет пользовательского ввода — параметризация не нужна
  );

  return (
    <main>
      <h1>Посты</h1>
      <PostList posts={posts} />
    </main>
  );
}

// components/PostList.tsx — Server Component
type Post = { id: string; title: string; author_id: string };

export async function PostList({ posts }: { posts: Post[] }) {
  return (
    <ul>
      {posts.map(post => (
        <li key={post.id}>
          <span>{post.title}</span>
          {/* LikeButton — Client Component, гидрируется только это поддерево */}
          <LikeButton postId={post.id} />
        </li>
      ))}
    </ul>
  );
}

// components/LikeButton.tsx — Client Component (использует state/события)
'use client';
import { useState } from 'react';

export function LikeButton({ postId }: { postId: string }) {
  const [liked, setLiked] = useState(false);
  return (
    <button
      onClick={async () => {
        setLiked(l => !l);
        await fetch(`/api/posts/${postId}/like`, { method: 'POST' });
      }}
      aria-pressed={liked}
    >
      {liked ? '♥ Нравится' : '♡ Нравится'}
    </button>
  );
}

// Паттерн "пончик": Client Component-оболочка, Server Component-контент внутри через children
'use client';
import { useState, type ReactNode } from 'react';

export function CollapsibleSection({ children, title }: { children: ReactNode; title: string }) {
  const [open, setOpen] = useState(true);
  return (
    <section>
      <button onClick={() => setOpen(o => !o)}>{title}</button>
      {open && children}   {/* children может быть выводом Server Component */}
    </section>
  );
}
```

**Типичная ошибка на интервью:** Импортировать Server Component внутри Client Component — это тянет серверные модули (клиенты БД, API файловой системы) в клиентский бандл и вызывает ошибку сборки. Правильный паттерн — передавать серверный контент *как пропсы* (`children` или именованные слоты) из родительского Server Component в оболочку Client Component. Это паттерн «пончика» (donut composition).

answer.en:
### Hydration Mismatch Debugging

Hydration mismatch occurs when server-rendered HTML differs from client-rendered content. Debug by checking for Date/Math.random(), conditional rendering based on typeof window, or missing keys in lists.

```typescript
// ❌ Problem: Date differs on server vs client
function Component() {
  return <div>{new Date().toISOString()}</div>;
}

// ✅ Solution: Suppress hydration on first render
function Component() {
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);
  return <div>{mounted ? new Date().toISOString() : null}</div>;
}
```

**Common interview trap:** Assuming hydration mismatch only affects performance—it breaks interactivity and causes console errors.

answer.ru:
### Отладка несоответствия гидрации

Несоответствие гидрации возникает когда HTML на сервере отличается от контента на клиенте. Отлаживайте, проверяя Date/Math.random(), условный рендеринг на основе typeof window или отсутствующие keys в списках.

```typescript
// ❌ Проблема: Date различается на сервере и клиенте
function Component() {
  return <div>{new Date().toISOString()}</div>;
}

// ✅ Решение: Подавите гидрацию на первом рендере
function Component() {
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);
  return <div>{mounted ? new Date().toISOString() : null}</div>;
}
```

**Типичная ошибка:** Предположение что несоответствие гидрации влияет только на производительность—оно нарушает интерактивность и вызывает ошибки консоли.

answer.en:
### React Forget (React Compiler)

React Forget automatically memoizes values and callbacks at the compiler level, eliminating the need for manual useMemo/useCallback. It analyzes data dependencies and optimizes renders without developer intervention.

```typescript
// Before: Manual memoization required
const MemoizedComponent = memo(function Comp({ data }) {
  const handleClick = useCallback(() => {}, []);
  return <button onClick={handleClick}>{data}</button>;
});

// After: Compiler handles it automatically
function Comp({ data }) {
  return <button onClick={() => {}}>{data}</button>;
}
```

**Common interview trap:** React Forget doesn't eliminate the need for good component architecture—it just removes boilerplate memoization.

answer.ru:
### React Forget (React Compiler)

React Forget автоматически мемоизирует значения и коллбеки на уровне компилятора, исключая необходимость в ручных useMemo/useCallback. Он анализирует зависимости данных и оптимизирует рендеры без вмешательства разработчика.

```typescript
// До: Требуется ручная мемоизация
const MemoizedComponent = memo(function Comp({ data }) {
  const handleClick = useCallback(() => {}, []);
  return <button onClick={handleClick}>{data}</button>;
});

// После: Компилятор обрабатывает автоматически
function Comp({ data }) {
  return <button onClick={() => {}}>{data}</button>;
}
```

**Типичная ошибка:** React Forget не исключает необходимость хорошей архитектуры компонентов—он просто убирает boilerplate мемоизацию.

answer.en:
### Custom Renderers

Custom renderers use React Reconciler to target non-DOM environments (React Native, Skia, Canvas). You implement hostConfig callbacks (createInstance, appendChild) mapping React elements to your target platform.

```typescript
// Minimal custom renderer example
import ReactReconciler from 'react-reconciler';

const hostConfig = {
  createInstance(type, props) {
    return { type, props, children: [] };
  },
  appendChild(parent, child) {
    parent.children.push(child);
  },
  // ... 20+ more methods required
};

const renderer = ReactReconciler(hostConfig);
```

**Common interview trap:** Thinking React Reconciler is React's internal only—it's a public API designed for custom platforms.

answer.ru:
### Пользовательские рендеры

Пользовательские рендеры используют React Reconciler для нацеливания на не-DOM окружения (React Native, Skia, Canvas). Вы реализуете коллбеки hostConfig (createInstance, appendChild) отображающие элементы React на целевую платформу.

```typescript
// Минимальный пример пользовательского рендера
import ReactReconciler from 'react-reconciler';

const hostConfig = {
  createInstance(type, props) {
    return { type, props, children: [] };
  },
  appendChild(parent, child) {
    parent.children.push(child);
  },
  // ... требуется 20+ дополнительных методов
};

const renderer = ReactReconciler(hostConfig);
```

**Типичная ошибка:** Предположение что React Reconciler только для внутреннего использования React—это публичный API для пользовательских платформ.
